mapper.update:
/* com.educare.edu.comn.mapper.AttendDayStdntMapper.updateByPk */
	update t_attend_day_stdnt
	set upd_de = #{updDe} ,upd_id = #{updId} 
	 	,att_cd		= #{attCd} 
	 		,att_tp		= #{attTp} 
	 ,begin_de	= #{beginDe} 
	 	,end_de		= #{endDe} 
	 	,at1_cd		= #{at1Cd} 
	 	,at2_cd		= #{at2Cd} 
	 	,at3_cd		= #{at3Cd} 
	 	,at1_de		= #{at1De} 
	 	,at2_de		= #{at2De} 
	 	,at3_de		= #{at3De} 
	where edu_seq=#{eduSeq} and edu_dt=#{eduDt} and user_id=#{userId}
